import inspect
src = inspect.getsource(is_number)
forbidden = ['float(', 'int(', 'import re', 'from re ']
for f in forbidden:
    assert f not in src, f'forbidden {f} found'
for s in ['0','0.1','1.','.1','-1','+1','3.14','2e10','-2E-10','+6e+1','.5','5.','1e0']:
    assert is_number(s) is True, f'should be True: {s!r}'
for s in ['','.','e','E','e1','+','-','1e','1e+','1a','.e1','1.2.3','++1','+-1','1 ','1.0 ',' 1',' ','.-1','abc','1e1.5','--1']:
    assert is_number(s) is False, f'should be False: {s!r}'
